import{_ as e,W as t,X as o,Y as a}from"./framework-8bc9c5c2.js";const i={},n=a('<p>Manchester United’s <code>humiliations</code> at the hands of their biggest <code>rivals</code> were supposed to have been <code>confined</code> to last season. But on an afternoon when Liverpool <code>relocated</code> something that has seemed lost at times, <code>sparking</code> what they believe can be a successful push for a top-four Premier League finish, United were <code>reacquainted</code> with their worst nightmares. This was even worse than the horrors of the previous <code>campaign</code> mainly because they had made the short journey to Anfield on a high, having lost only once in 22 matches, collecting the Carabao Cup in the process.</p><div class="hint-container info"><p class="hint-container-title">tips</p><p>humiliation：耻辱，丢脸（humiliate 使丢脸，屈辱）</p><p>rival：对手，竞争者（rivalry 竞争，对抗；unrivalled 无双的，无可匹敌的）</p><p>confind：限制，监禁（con 全部，fin 限制）</p><p>last season：不是最后一个赛季，是上个赛季</p><p>relocate：重新安置，放在新地方（locate 找出，定位）</p><p>spark：n. 火花；vi 闪光，鼓舞</p><p>reacquaint：重新认识（acquaint 介绍）</p><p>were <code>reacquainted</code> with their worst nightmares：重温噩梦</p></div>',2),s=[n];function c(r,h){return t(),o("div",null,s)}const p=e(i,[["render",c],["__file","2303071929.html.vue"]]);export{p as default};
